module top_module(Inv_A, B, AeqB, AgtB, AltB);input [3:0] Inv_A;
	input [3:0] B;
	output AeqB, AgtB, AltB;
	reg AeqB, AgtB, AltB;

	always @(Inv_A or B)
	begin

		if(Inv_A == B)
			AeqB = 1;
		else 
			AeqB = 0; 

		if (Inv_A > B)
			AgtB = 1;
		else 
			AgtB = 0; 

		if (Inv_A < B) 
			AltB = 1;
		else
			AltB = 0;
	end
endmodule
